mapper.select:
SELECT DISTINCT forecast_date
FROM marine_forecasts
WHERE experience = #{experience}
	AND forecast_date >= #{baseDate}
ORDER BY forecast_date ASC

SELECT EXISTS (
	SELECT 1
	FROM ai_spot_recommendations
	WHERE experience = #{experience}
		AND forecast_date = #{forecastDate}
)

mapper.delete:
DELETE FROM ai_spot_recommendations
WHERE experience = #{experience}
	AND forecast_date = #{forecastDate}

mapper.select:
SELECT r.spot_id AS spotId, r.experience, s.name AS spotName, s.region, r.forecast_date AS forecastDate, mf.time_slot AS timeSlot, mf.total_index AS totalIndex, s.post_count AS postCount, CASE WHEN fs.id IS NULL THEN FALSE ELSE TRUE END AS favorite, CAST(mf.metrics AS CHAR) AS metrics, r.rank_no AS `rank`, r.reason, r.generated_at AS generatedAt FROM ai_spot_recommendations r JOIN spots s ON s.id = r.spot_id LEFT JOIN marine_forecasts mf ON mf.spot_id = r.spot_id AND mf.forecast_date = r.forecast_date AND mf.id = ( SELECT mf2.id FROM marine_forecasts mf2 WHERE mf2.spot_id = r.spot_id AND mf2.forecast_date = r.forecast_date ORDER BY mf2.time_slot ASC, mf2.id ASC LIMIT 1 ) LEFT JOIN favorite_spots fs ON fs.spot_id = r.spot_id AND fs.user_id = #{userId} WHERE r.experience = #{experience}
AND r.forecast_date = #{targetDate}
AND r.generated_at = ( SELECT MAX(r2.generated_at) FROM ai_spot_recommendations r2 WHERE r2.experience = #{experience} )
ORDER BY r.rank_no ASC
